  import sailpoint.tools.Util;

  if(Util.isNotNullOrEmpty(workflowTrigger) && workflowTrigger.equalsIgnoreCase("rule")){
      return true;
  }
  return false;

	    
        import sailpoint.transformer.IdentityTransformer;
        Map identityModel = new HashMap();
        if(null != identityModel){
          identityModel.put("launcher",launcher);     
        }    
        IdentityTransformer transformer = new IdentityTransformer(context);
        identityModel.put(IdentityTransformer.ATTR_TRANSFORMER_CLASS, transformer.getClass().getName());
        identityModel.put(IdentityTransformer.ATTR_TRANSFORMER_OPTIONS, "");
        return identityModel;

	  
        String idName = "";
        if(null != identityModel){
          idName = identityModel.get("userName");     
        }    
        return idName;

	  
        import sailpoint.object.Identity;
        
        Identity identity = context.getObjectByName(Identity.class,identityName);
        
        if(null != identity){       
          identity.setAttribute("manualTerm","Yes");
          context.saveObject(identity);
          context.commitTransaction();
        }

  import sailpoint.tools.Util;

  if(Util.isNotNullOrEmpty(workflowTrigger) && workflowTrigger.equalsIgnoreCase("rule")){
      return true;
  }
  return false;

			  
			    import java.lang.StringBuilder;
                import sailpoint.object.Form;
                import sailpoint.object.Field;
                import sailpoint.tools.Util;

                Field requesterHeader= form.getField("requesterHeader");
                requesterHeader.setDisplayName("");

                StringBuilder builder = new StringBuilder();
                builder.append("This user will be disabled immediately, are you sure you want to proceed?");

                return builder.toString();

			  
                import sailpoint.object.Identity;
                import sailpoint.object.ProvisioningPlan;
                import sailpoint.object.ProvisioningPlan.AccountRequest;

                Identity identity = context.getObjectByName(Identity.class,identityName);
                String fullName ="";
                
                if(null != identity){              
                  fullName = identity.getLastname()+","+identity.getFirstname(); 
                }
                return fullName;

		
          import sailpoint.object.IdentityTrigger;
          IdentityTrigger idtyTrigger = context.getObjectByName(IdentityTrigger.class,"LEAVER FEATURE");
           return idtyTrigger;

		
        import sailpoint.object.IdentityTrigger;
        import sailpoint.object.IdentityChangeEvent;
        import sailpoint.object.Identity;
                   
        Identity idty = context.getObjectByName(Identity.class,identityName);
        IdentityTrigger idtyTrigger = context.getObjectByName(IdentityTrigger.class,"LEAVER FEATURE");
        IdentityChangeEvent idtyEvent = new IdentityChangeEvent();
        if(null != idtyTrigger){                     
          idtyEvent = idtyTrigger.createEvent(idty,idty);
        }    
        return idtyEvent;

import sailpoint.object.Attributes;
import sailpoint.object.AuditEvent;
import sailpoint.server.Auditor;

AuditEvent auditEvent = new AuditEvent();
Attributes attrsMap = new Attributes();
attrsMap.put("requester", launcher);
attrsMap.put("requestee", identityName);
auditEvent = new AuditEvent("ImmediateDisablement Request", "Comment", identityName);
auditEvent.setApplication("IIQ");
auditEvent.setAccountName(identityName);
auditEvent.setAttributes(attrsMap);
Auditor.log(auditEvent);
context.commitTransaction();
